import math

def ternary_search(f, left, right, eps=1e-7, find_max=True):
    while right - left > eps:
        m1 = left + (right - left) / 3
        m2 = right - (right - left) / 3

        if find_max:
            if f(m1) < f(m2):
                left = m1
            else:
                right = m2
        else: # find_min
            if f(m1) < f(m2):
                right = m2
            else:
                left = m1
    return (left + right) / 2
